+async fn distributed_agent_seed_gap_cursors(
+    storage: &Arc<
+        frankenterm_core::runtime_compat::Mutex<frankenterm_core::storage::StorageHandle>,
+    >,
+    cursors: &mut std::collections::HashMap<u64, i64>,
